params.script:
// Script Template: business_hours
// 現在時刻が営業時間内か判定
// プレースホルダー: 13, 16 = 営業開始/終了時刻（24時間制、0-23）
// 出力: 営業時間内 / 営業時間外

var now = new Date();
var hour = now.getHours();
var startHour = 13;
var endHour = 16;
var res = "営業時間外";

if (hour >= startHour && hour < endHour) {
    res = "営業時間内";
}

$runner.setResult(res);
